// Mock worker
const mockStartWorker = jest.fn();
const mockStopWorker = jest.fn();
jest.mock('../../src/workers/analysis.worker', () => ({
  startAnalysisWorker: () => mockStartWorker(),
  stopAnalysisWorker: () => mockStopWorker(),
